 Run custom code at key points in the agent lifecycle. SDK hooks use callback functions to validate, log, block, or transform agent behavior.

 \*\*Available hooks:\*\* \`PreToolUse\`, \`PostToolUse\`, \`Stop\`, \`SessionStart\`, \`SessionEnd\`, \`UserPromptSubmit\`, and more.

 This example logs all file changes to an audit file:


 \`\`\`python Python theme={null}
 import asyncio
 from datetime import datetime
 from claude\_agent\_sdk import query, ClaudeAgentOptions, HookMatcher

 async def log\_file\_change(input\_data, tool\_use\_id, context):
 file\_path = input\_data.get("tool\_input", {}).get("file\_path", "unknown")
 with open("./audit.log", "a") as f:
 f.write(f"{datetime.now()}: modified {file\_path}\\n")
 return {}

 async def main():
 async for message in query(
 prompt="Refactor utils.py to improve readability",
 options=ClaudeAgentOptions(
 permission\_mode="acceptEdits",
 hooks={
 "PostToolUse": \[\
 HookMatcher(matcher="Edit\|Write", hooks=\[log\_file\_change\])\
 \]
 },
 ),
 ):
 if hasattr(message, "result"):
 print(message.result)

 asyncio.run(main())
 \`\`\`

 \`\`\`typescript TypeScript theme={null}
 import { query, HookCallback } from "@anthropic-ai/claude-agent-sdk";
 import { appendFile } from "fs/promises";

 const logFileChange: HookCallback = async (input) => {
 const filePath = (input as any).tool\_input?.file\_path ?? "unknown";
 await appendFile("./audit.log", \`${new Date().toISOString()}: modified ${filePath}\\n\`);
 return {};
 };

 for await (const message of query({
 prompt: "Refactor utils.py to improve readability",
 options: {
 permissionMode: "acceptEdits",
 hooks: {
 PostToolUse: \[{ matcher: "Edit\|Write", hooks: \[logFileChange\] }\]
 }
 }
 })) {
 if ("result" in message) console.log(message.result);
 }
 \`\`\`


